-- Seed Agent Identities for all 60 platform agents with realistic metrics


-- Seed economics data for last 30 days for top agents
SELECT 
  ai.id,
  CURRENT_DATE - (d || ' days')::interval,
  (random() * 2000 + 500)::int,
  (random() * 1800 + 450)::int,
  (random() * 50 + 5)::int,
  (random() * 1500 + 200)::int,
  (random() * 20 + 2)::int,
  (random() * 100 + 10)::int,
  random() * 15 + 2,
  random() * 180 + 30,
  random() * 6 + 1,
  random() * 50000 + 5000
FROM agent_identities ai
CROSS JOIN generate_series(0, 29) AS d
WHERE ai.lifecycle_state = 'active'
AND ai.trust_score > 92;

-- Seed lifecycle events
SELECT id, 'created', NULL, 'draft', 'system', 'Agent registered in platform'
FROM agent_identities;

SELECT id, 'approved', 'pending_review', 'approved', 'admin@0xdsi.com', 'Passed security review and testing'
FROM agent_identities WHERE lifecycle_state = 'active';

SELECT id, 'activated', 'approved', 'active', 'orchestrator', 'Deployed to production cluster'
FROM agent_identities WHERE lifecycle_state = 'active';
